// Shelf Frontend Worker — Monochrome Brutalist Redesign
const ASSETS = {
  '/': { data: '', type: 'text/html; charset=utf-8' },
  '/index.html': { data: '', type: 'text/html; charset=utf-8' },
  '/assets/index-CKptFCdR.css': { data: '', type: 'text/css; charset=utf-8' },
  '/assets/index-BajAa8yu.js': { data: '', type: 'application/javascript; charset=utf-8' },
}

const MANIFEST = JSON.stringify({
  name: 'Shelf',
  short_name: 'Shelf',
  start_url: '/',
  display: 'standalone',
  background_color: '#0a0a0a',
  theme_color: '#0a0a0a',
})

export default {
  async fetch(request) {
    const url = new URL(request.url)
    let path = url.pathname

    if (path === '/manifest.json') {
      return new Response(MANIFEST, {
        headers: { 'Content-Type': 'application/manifest+json', 'Cache-Control': 'public, max-age=86400' },
      })
    }

    const asset = ASSETS[path] || ASSETS['/']
    const body = Uint8Array.from(atob(asset.data), c => c.charCodeAt(0))
    return new Response(body, {
      headers: {
        'Content-Type': asset.type,
        'Cache-Control': path.startsWith('/assets/') ? 'public, max-age=31536000, immutable' : 'public, max-age=300',
        'X-Content-Type-Options': 'nosniff',
      },
    })
  },
}
